#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    /* Implement the filtering, settling, and draining state machine */
    switch (input.kind) {
    case CONTROLLER_INPUT_TURBIDITY:
        if (input.turbidity_ntu <= 35 && input.level >= 40) {
            /* Clear turbidity while level is high - start clear streak */
            controller->clear_streak_count++;
            controller->last_turbidity_ntu = input.turbidity_ntu;
            controller->last_turbidity_ms = input.now_ms;
        } else if (input.turbidity_ntu > 35) {
            /* Turbidity is high - reset clear streak */
            controller->clear_streak_count = 0;
        }
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;

        /* Check for settling conditions - need at least 3 clear samples */
        if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED &&
            controller->state == CONTROLLER_STATE_SAFE_IDLE &&
            controller->has_valid_level &&
            input.level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            /* Check if we've been in filtering for enough time to start settling */
            uint32_t elapsed_ms = (input.now_ms - controller->last_turbidity_ms);
            if (elapsed_ms > CONTROLLER_SETTLING_MS) {
                /* Start settling timer */
                controller->settling_started_ms = input.now_ms;
            }
        }

        /* Check if we should start draining */
        if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED &&
            controller->has_valid_level &&
            input.level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            /* If settling has started, wait for 400ms of clear samples */
            uint32_t elapsed_ms = (input.now_ms - controller->settling_started_ms);
            if (elapsed_ms >= CONTROLLER_SETTLING_MS &&
                controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED &&
                input.level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                /* Drain open conditions met */
                output.filter_on = false;
                output.drain_open = true;
                output.state = CONTROLLER_STATE_DRAINING;
                output.state_name = "STATE DRAINING";
            } else if (elapsed_ms >= CONTROLLER_SETTLING_MS) {
                /* Settling complete, drain open */
                output.filter_on = false;
                output.drain_open = true;
                output.state = CONTROLLER_STATE_DRAINING;
                output.state_name = "STATE DRAINING";
            } else {
                /* Still in filtering - don't open drain yet */
                output.filter_on = controller->filter_on;
                output.drain_open = controller->drain_open;
                output.state = CONTROLLER_STATE_FILTERING;
                output.state_name = "STATE FILTERING";
            }
        } else {
            /* Still filtering - don't open drain yet */
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = CONTROLLER_STATE_FILTERING;
            output.state_name = "STATE FILTERING";
        }

        break;

    case CONTROLLER_INPUT_LEVEL:
        if (input.level < 15) {
            /* Level is too low - stay in complete state */
            output.filter_on = false;
            output.drain_open = false;
            output.state = CONTROLLER_STATE_COMPLETE;
            output.state_name = "STATE COMPLETE";
            output.changed = true;
        } else if (input.level >= 40) {
            /* High level - stay in complete state */
            output.filter_on = false;
            output.drain_open = false;
            output.state = CONTROLLER_STATE_COMPLETE;
            output.state_name = "STATE COMPLETE";
            output.changed = true;
        } else if (input.level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            /* Level is in the process of draining - check for clear streak */
            controller->has_valid_level = true;
            controller->last_level = input.level;
            controller->last_level_ms = input.now_ms;

            /* Check if we should start draining */
            if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED &&
                controller->state == CONTROLLER_STATE_SAFE_IDLE &&
                input.level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                /* Start settling timer */
                controller->settling_started_ms = input.now_ms;
            }

            /* Check if we should start draining */
            if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED &&
                controller->state == CONTROLLER_STATE_SAFE_IDLE &&
                input.level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                /* If settling has started, wait for 400ms of clear samples */
                uint32_t elapsed_ms = (input.now_ms - controller->settling_started_ms);
                if (elapsed_ms >= CONTROLLER_SETTLING_MS &&
                    controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED &&
                    input.level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                    /* Drain open conditions met */
                    output.filter_on = false;
                    output.drain_open = true;
                    output.state = CONTROLLER_STATE_DRAINING;
                    output.state_name = "STATE DRAINING";
                } else if (elapsed_ms >= CONTROLLER_SETTLING_MS) {
                    /* Settling complete, drain open */
                    output.filter_on = false;
                    output.drain_open = true;
                    output.state = CONTROLLER_STATE_DRAINING;
                    output.state_name = "STATE DRAINING";
                } else {
                    /* Still in filtering - don't open drain yet */
                    output.filter_on = controller->filter_on;
                    output.drain_open = controller->drain_open;
                    output.state = CONTROLLER_STATE_FILTERING;
                    output.state_name = "STATE FILTERING";
                }
            } else {
                /* Still filtering - don't open drain yet */
                output.filter_on = controller->filter_on;
                output.drain_open = controller->drain_open;
                output.state = CONTROLLER_STATE_FILTERING;
                output.state_name = "STATE FILTERING";
            }
        } else {
            /* Level is too low - stay in complete state */
            output.filter_on = false;
            output.drain_open = false;
            output.state = CONTROLLER_STATE_COMPLETE;
            output.state_name = "STATE COMPLETE";
            output.changed = true;
        }

        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_TURBIDITY:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        /* Timeout or invalid input - reset everything to safe idle */
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);

        break;

    case CONTROLLER_INPUT_NONE:
    default:
        /* Invalid input - reset to safe idle */
        controller_set_safe_idle(controller);

        break;
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_filter_on != controller->filter_on) ||
        (previous_drain_open != controller->drain_open) ||
        (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

/* Firmware-level end-to-end probe for UART testing */
bool firmware_probe(controller_t *controller, const char *command_line, int command_len)
{
    if (controller == 0 || command_len <= 0) {
        return false;
    }

    /* Reset to safe idle first */
    controller_set_safe_idle(controller);

    /* Parse the command line into a protocol input */
    uint8_t buf[128];
    int cmd_idx = 0;
    int parsed_len = 0;

    for (int i = 0; i < command_len && i < 127; i++) {
        if (command_line[i] == '\0') break;
        buf[parsed_len++] = command_line[i];
    }
    buf[parsed_len] = '\0';

    /* Try to parse the command as a protocol line */
    int parsed_result = 0;
    uint8_t *input_buf = (uint8_t *)buf;
    controller_input_t input;

    if (parsed_result == PROTOCOL_PARSE_TURBIDITY) {
        parsed_len = strlen("SENSE TURB ");
        for (int i = 0; i < parsed_len; i++) {
            buf[i] = command_line[parsed_idx + i];
        }
        input.kind = CONTROLLER_INPUT_TURBIDITY;
        input.turbidity_ntu = atoi(buf);
        input.now_ms = 0;
    } else if (parsed_result == PROTOCOL_PARSE_LEVEL) {
        parsed_len = strlen("SENSE LEVEL ");
        for (int i = 0; i < parsed_len; i++) {
            buf[i] = command_line[parsed_idx + i];
        }
        input.kind = CONTROLLER_INPUT_LEVEL;
        input.level = atoi(buf);
        input.now_ms = 0;
    } else if (parsed_result == PROTOCOL_PARSE_SENSOR_TIMEOUT) {
        parsed_len = strlen("FAULT SENSOR_TIMEOUT");
        for (int i = 0; i < parsed_len; i++) {
            buf[i] = command_line[parsed_idx + i];
        }
        input.kind = CONTROLLER_INPUT_SENSOR_TIMEOUT;
        input.now_ms = 0;
    } else {
        return false;
    }

    /* Execute the probe */
    controller_output_t output = controller_step(controller, input);

    if (output.timed_out) {
        return false;
    }

    /* Check if we're in a valid state for testing */
    switch (output.state) {
    case CONTROLLER_STATE_SAFE_IDLE:
    case CONTROLLER_STATE_COMPLETE:
        return true;  /* Probe successful, no errors */
    case CONTROLLER_STATE_FILTERING:
    case CONTROLLER_STATE_SETTLING:
    case CONTROLLER_STATE_DRAINING:
        return true;  /* Probe successful, no errors */
    default:
        return false;  /* Probe failed - in unexpected state */
    }
}

